M.Aggregation.callTemplate:
agg_fn <- switch("<agg_func>",
  sum = function(x) sum(x, na.rm = TRUE),
  count = function(x) sum(!is.na(x)),
  mean = function(x) mean(x, na.rm = TRUE),
  max = function(x) max(x, na.rm = TRUE),
  min = function(x) min(x, na.rm = TRUE),
  function(x) sum(x, na.rm = TRUE)
)
partition_cols <- strsplit("<partition>", " \\+ ")[[1]]
partition_cols <- partition_cols[partition_cols %in% colnames(concept_data)]
val_col <- "<value>"
if (length(partition_cols) > 0 && val_col %in% colnames(concept_data)) {
  agg_result <- aggregate(
    stats::as.formula(paste0("`", val_col, "` ~ ", paste0("`", partition_cols, "`", collapse = " + "))),
    data = concept_data, FUN = agg_fn
  )
  colnames(agg_result)[colnames(agg_result) == val_col] <- "<result>"
  concept_data <- merge(concept_data, agg_result, by = partition_cols, all.x = TRUE)
} else if (val_col %in% colnames(concept_data)) {
  concept_data[["<result>"]] <- agg_fn(as.numeric(concept_data[[val_col]]))
}
